/**
 * env.js — Runtime environment configuration for CloudSentinel
 *
 * Generated by Terraform after deploy. Update these values from terraform output.
 * NEVER hardcode region, account IDs, or credentials here.
 */

window.ENV_COGNITO_POOL_ID      = "";   // e.g. us-east-1_XXXXXXXX
window.ENV_COGNITO_CLIENT_ID    = "";   // Cognito App Client ID
window.ENV_API_URL              = "";   // https://XXXXX.execute-api.us-east-1.amazonaws.com/dev
window.ENV_REGION               = "";   // Platform region (us-east-1)
window.ENV_CFN_TEMPLATE_URL     = "";   // S3 URL of scanner-role.yaml
window.ENV_PLATFORM_ACCOUNT_ID  = "";   // Platform AWS account ID
window.ENV_LAMBDA_ROLE_NAME     = "cloudsentinel-lambda-role";
